import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

// Props mein setToken aur setIsAdmin le rahe hain connectivity ke liye
function Login({ setToken, setIsAdmin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      // Backend connectivity call
      const response = await axios.post('http://127.0.0.1:8000/api/login', { 
        username, 
        password 
      });

      // 1. Token aur Admin status ko storage mein save karein
      localStorage.setItem('token', response.data.access_token);
      localStorage.setItem('is_admin', response.data.is_admin);

      // 2. App.js ki state update karein (taaki dashboard turant dikhe)
      setToken(response.data.access_token);
      setIsAdmin(response.data.is_admin === true || response.data.is_admin === 1);

      alert("Login Successful! Welcome back.");
      navigate('/'); // React-router ka sahi tarika redirect karne ka
    } catch (err) {
      console.error(err);
      alert("Invalid Username or Password. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-page">
      <div className="form-container">
        <h2 className="page-title">Grievance Portal Login</h2>
        <p style={{ color: '#666', marginBottom: '20px' }}>Apne account mein login karein</p>

        <form onSubmit={handleLogin}>
          <input 
            className="form-input"
            type="text" 
            placeholder="Username" 
            value={username}
            onChange={(e) => setUsername(e.target.value)} 
            required 
          />

          <input 
            className="form-input"
            type="password" 
            placeholder="Password" 
            value={password}
            onChange={(e) => setPassword(e.target.value)} 
            required 
          />

          <button 
            type="submit" 
            className="submit-btn"
            disabled={loading}
          >
            {loading ? "Logging in..." : "Login"}
          </button>
        </form>

        <p style={{ marginTop: '15px', fontSize: '14px' }}>
          Account nahi hai? <span style={{ color: '#1e3c72', cursor: 'pointer', fontWeight: 'bold' }} onClick={() => navigate('/signup')}>Signup Karein</span>
        </p>
      </div>
    </div>
  );
}

export default Login;
